import { useState } from 'react';
import './App.css';
import Admin from './pages/Admin';

const initialProducts = [
  { id: 1, name: '신선 사과', price: 5000, category: '식품' },
  { id: 2, name: '제주 감귤', price: 8000, category: '식품' },
  { id: 3, name: '세탁 세제', price: 12000, category: '생활용품' },
  { id: 4, name: '콜라 1.5L', price: 3000, category: '음료' },
  { id: 5, name: '냉동 만두', price: 7000, category: '냉동식품' },
  { id: 6, name: '포카칩', price: 2500, category: '과자/간식' },
];

function App() {
  const [page, setPage] = useState('home');
  const [products, setProducts] = useState(initialProducts);
  const [cart, setCart] = useState([]);

  const addToCart = (product) => {
    const existing = cart.find((item) => item.id === product.id);
    if (existing) {
      setCart(cart.map((item) =>
        item.id === product.id
          ? { ...item, quantity: item.quantity + 1 }
          : item
      ));
    } else {
      setCart([...cart, { ...product, quantity: 1 }]);
    }
    alert(`${product.name}이(가) 장바구니에 담겼어요! 🛒`);
  };

  const removeFromCart = (id) => {
    setCart(cart.filter((item) => item.id !== id));
  };

  const totalPrice = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);

  return (
    <div className="App">
      <header style={{ background: '#1a73e8', padding: '16px 24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h1 style={{ color: 'white', margin: 0, fontSize: '24px', cursor: 'pointer' }} onClick={() => setPage('home')}>🛒 SR Mart</h1>
        <nav style={{ display: 'flex', gap: '16px', alignItems: 'center' }}>
          <span onClick={() => setPage('home')} style={{ color: 'white', cursor: 'pointer' }}>홈</span>
          <span onClick={() => setPage('home')} style={{ color: 'white', cursor: 'pointer' }}>상품</span>
          <span onClick={() => setPage('cart')} style={{ color: 'white', cursor: 'pointer' }}>
            🛒 장바구니 {cart.length > 0 && (
              <span style={{ background: '#e53935', borderRadius: '50%', padding: '2px 7px', fontSize: '12px', marginLeft: '4px' }}>
                {cart.length}
              </span>
            )}
          </span>
          <span onClick={() => setPage('admin')} style={{ color: '#ffd54f', cursor: 'pointer', fontWeight: 'bold' }}>관리자</span>
        </nav>
      </header>

      {page === 'home' && (
        <main style={{ padding: '24px' }}>
          <h2 style={{ marginBottom: '16px' }}>추천 상품</h2>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '16px' }}>
            {products.map((product) => (
              <div key={product.id} style={{ border: '1px solid #ddd', borderRadius: '8px', padding: '16px', textAlign: 'center' }}>
                <div style={{ background: '#f5f5f5', height: '120px', borderRadius: '4px', marginBottom: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '32px' }}>🛍️</div>
                <p style={{ fontSize: '12px', color: '#888', margin: '0 0 4px' }}>{product.category}</p>
                <h3 style={{ margin: '0 0 8px' }}>{product.name}</h3>
                <p style={{ color: '#1a73e8', fontWeight: 'bold', margin: '0 0 12px' }}>₩{product.price.toLocaleString()}</p>
                <button
                  onClick={() => addToCart(product)}
                  style={{ background: '#1a73e8', color: 'white', border: 'none', borderRadius: '4px', padding: '8px 16px', cursor: 'pointer', width: '100%' }}>
                  장바구니 담기
                </button>
              </div>
            ))}
          </div>
        </main>
      )}

      {page === 'cart' && (
        <main style={{ padding: '24px', maxWidth: '700px', margin: '0 auto' }}>
          <h2 style={{ marginBottom: '24px' }}>🛒 장바구니</h2>
          {cart.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '60px', color: '#888' }}>
              <p style={{ fontSize: '48px' }}>🛒</p>
              <p>장바구니가 비어있어요!</p>
              <button onClick={() => setPage('home')} style={{ marginTop: '16px', padding: '10px 24px', background: '#1a73e8', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>
                쇼핑 계속하기
              </button>
            </div>
          ) : (
            <>
              <table style={{ width: '100%', borderCollapse: 'collapse', marginBottom: '24px' }}>
                <thead>
                  <tr style={{ background: '#1a73e8', color: 'white' }}>
                    <th style={{ padding: '12px', textAlign: 'left' }}>상품명</th>
                    <th style={{ padding: '12px', textAlign: 'center' }}>수량</th>
                    <th style={{ padding: '12px', textAlign: 'right' }}>금액</th>
                    <th style={{ padding: '12px', textAlign: 'center' }}>삭제</th>
                  </tr>
                </thead>
                <tbody>
                  {cart.map((item) => (
                    <tr key={item.id} style={{ borderBottom: '1px solid #ddd' }}>
                      <td style={{ padding: '12px' }}>{item.name}</td>
                      <td style={{ padding: '12px', textAlign: 'center' }}>{item.quantity}개</td>
                      <td style={{ padding: '12px', textAlign: 'right', color: '#1a73e8', fontWeight: 'bold' }}>₩{(item.price * item.quantity).toLocaleString()}</td>
                      <td style={{ padding: '12px', textAlign: 'center' }}>
                        <button onClick={() => removeFromCart(item.id)} style={{ background: '#e53935', color: 'white', border: 'none', borderRadius: '4px', padding: '6px 12px', cursor: 'pointer' }}>삭제</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              <div style={{ textAlign: 'right', borderTop: '2px solid #1a73e8', paddingTop: '16px' }}>
                <p style={{ fontSize: '20px', fontWeight: 'bold' }}>총 합계: ₩{totalPrice.toLocaleString()}</p>
                <button style={{ marginTop: '12px', padding: '14px 32px', background: '#1a73e8', color: 'white', border: 'none', borderRadius: '4px', fontSize: '16px', cursor: 'pointer' }}>
                  주문하기
                </button>
              </div>
            </>
          )}
        </main>
      )}

      {page === 'admin' && (
        <Admin products={products} setProducts={setProducts} />
      )}

      <footer style={{ background: '#333', color: 'white', padding: '24px', textAlign: 'center', marginTop: '40px' }}>
        <p style={{ margin: 0 }}>© 2026 SR Mart. All rights reserved.</p>
      </footer>
    </div>
  );
}

export default App;
